'use client';

import { useState } from 'react';
import Link from 'next/link';

export default function ProductCard({ 
  id,
  image, 
  title, 
  currentPrice, 
  originalPrice,
  isFavorite = false 
}) {
  const [favorite, setFavorite] = useState(isFavorite);

  return (
    <Link href={`/products/${id || 1}`} className="product-card-link">
      <div className="product-card">
        <div className="product-image-wrapper">
          <img
            src={image}
            alt={title}
            className="product-image"
          />
          <div 
            className={`product-favorite ${favorite ? 'active' : ''}`}
            onClick={(e) => {
              e.preventDefault();
              e.stopPropagation();
              setFavorite(!favorite);
            }}
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill={favorite ? "#FF0000" : "none"} stroke={favorite ? "#FF0000" : "#666666"} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path>
            </svg>
          </div>
        </div>
        <div className="product-info">
          <div className="product-title">{title}</div>
          <div className="product-price">
            <span className="product-price-current">{currentPrice}</span>
            {originalPrice && (
              <span className="product-price-original">{originalPrice}</span>
            )}
          </div>
        </div>
      </div>
    </Link>
  );
}

